sql:
SELECT COUNT(*) 
FROM standards 
WHERE region_id = 1 AND status = 'active';

SELECT component_name
FROM chemical_components
WHERE component_id = 0;

SELECT DISTINCT user_name
FROM users
WHERE is_active = 1 AND (role = 'safety officer' OR role = 'researcher');

SELECT COUNT(*) AS total_standards
FROM legal_bases
WHERE legal_jurisdiction = 'provincial';

SELECT component_name
FROM chemical_components
WHERE hazard_class = 'Toxic';

SELECT AVG(control_value) AS average_concentration
FROM standards
WHERE status = 'active';

SELECT AVG(control_value) AS average_control_value
FROM standards
WHERE date_adopted > '2023-01-01' AND status = 'active';

SELECT component_name
FROM chemical_components
ORDER BY component_name ASC;
